+
+/**
+ * Runs an agent to completion.  A delegated run stays internal: its text is
+ * returned to its parent as one tool_result instead of ending the user-facing
+ * stream.  This makes delegation recursive while retaining one public chat
+ * stream for the original agent.
+ */
+async function runAgent(
+  agentId: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: Set<string>,
+  isDelegated: boolean,
+): Promise<AgentRunResult> {
+  const events: StreamResponse[] = [];
+  const streamErrors: StreamResponse[] = [];
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+
+  if (!provider || !agentConfig) {
+    const error = `Agent '${agentId}' not found or provider not available`;
+    return { text: "", error, events, streamErrors: isDelegated ? [{ type: "error", error }] : [] };
+  }
+
+  const toolResultContext: NonNullable<ProviderChatRequest["context"]> = [];
+  let text = "";
+
+  // A tool result can cause the provider to continue its turn.  Repeat until
+  // a response contains no delegation request.
+  while (true) {
+    let delegatedThisTurn = false;
+    let providerError: string | undefined;
+    const providerRequest: ProviderChatRequest = {
+      message: request.message,
+      sessionId: request.sessionId,
+      requestId: request.requestId,
+      workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+      ...(toolResultContext.length ? { context: toolResultContext } : {}),
+    };
+
+    try {
+      for await (const response of provider.executeChat(providerRequest, {
+        debugMode,
+        abortController,
+        temperature: agentConfig.config?.temperature,
+        maxTokens: agentConfig.config?.maxTokens,
+      })) {
+        if (response.type === "text") {
+          text += response.content || "";
+          if (!isDelegated) {
+            const chatRoomMessage = createChatRoomMessage(response, agentId);
+            if (chatRoomMessage) {
+              events.push({ type: "claude_json", data: { type: "chat_room_message", message: chatRoomMessage, session_id: request.sessionId } });
+            }
+            events.push({ type: "claude_json", data: { type: "assistant", content: response.content, model: response.metadata?.model } });
+          }
+          continue;
+        }
+
+        if (response.type === "error") {
+          providerError = response.error || "Agent execution failed";
+          break;
+        }
+
+        if (response.type !== "tool_use" || response.toolName !== "delegate_task") {
+          continue;
+        }
+
+        delegatedThisTurn = true;
+        const toolUseId = response.toolUseId || `delegate-${agentId}-${toolResultContext.length + 1}`;
+        const input = (response.toolInput || {}) as DelegationInput;
+        const delegatedAgentId = typeof input.agent_id === "string" ? input.agent_id : "";
+        const instructions = typeof input.instructions === "string" ? input.instructions : "";
+        events.push(toolUseStreamResponse(response, toolUseId, request));
+
+        let delegatedResult: AgentRunResult;
+        if (!delegatedAgentId) {
+          const error = "delegate_task requires an agent_id";
+          delegatedResult = { text: "", error, events: [], streamErrors: [{ type: "error", error }] };
+        } else if (delegationPath.has(delegatedAgentId)) {
+          const error = `Circular agent delegation detected for '${delegatedAgentId}'`;
+          delegatedResult = { text: "", error, events: [], streamErrors: [{ type: "error", error }] };
+        } else {
+          const childRequest: ChatRequest = { ...request, message: instructions };
+          const childPath = new Set(delegationPath);
+          childPath.add(delegatedAgentId);
+          delegatedResult = await runAgent(
+            delegatedAgentId,
+            childRequest,
+            abortController,
+            debugMode,
+            childPath,
+            true,
+          );
+        }
+
+        streamErrors.push(...delegatedResult.streamErrors);
+        const toolResult = delegationToolResult(
+          toolUseId,
+          delegatedResult.error ? delegatedResult.error : delegatedResult.text || EMPTY_DELEGATION_RESULT,
+          Boolean(delegatedResult.error),
+        );
+        events.push(...delegatedResult.streamErrors, toolResultStreamResponse(toolResult, request));
+        toolResultContext.push({ role: "user", content: JSON.stringify(toolResult) });
