+      providerError = error instanceof Error ? error.message : String(error);
+    }
+
+    if (providerError) {
+      return { text, error: providerError, events, streamErrors };
+    }
+    if (!delegatedThisTurn) {
+      return { text, events, streamErrors };
+    }
+  }
