/**
 * Execute chat with a single agent
 */
async function* executeSingleAgent(
  agentId: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
): AsyncGenerator<StreamResponse> {
  // Handle special commands
  if (command?.command === "capture_screen") {
    yield* handleScreenCapture(
      agentId,
      request,
      command,
      abortController,
      debugMode,
    );
    return;
  }

  const result = await runAgent(
    agentId,
    request,
    abortController,
    debugMode,
    new Set([agentId]),
    false,
  );

  for (const event of result.events) {
    yield event;
  }

  if (result.error) {
    yield { type: "error", error: result.error };
  } else {
    yield { type: "done" };
  }
}

interface AgentRunResult {
  text: string;
  error?: string;
  events: StreamResponse[];
  streamErrors: StreamResponse[];
}

interface DelegationInput {
  agent_id?: unknown;
  instructions?: unknown;
}

const EMPTY_DELEGATION_RESULT =
  "[The delegated agent produced no textual output.]";

function delegationToolResult(
  toolUseId: string,
  content: string,
  isError: boolean,
) {
  return {
    type: "tool_result" as const,
    is_error: isError,
    content,
    tool_use_id: toolUseId,
  };
}

function toolUseStreamResponse(
  response: ProviderResponse,
  toolUseId: string,
  request: ChatRequest,
): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "assistant",
      message: {
        role: "assistant",
        content: [
          {
            type: "tool_use",
            id: toolUseId,
            name: response.toolName,
            input: response.toolInput || {},
          },
        ],
      },
      session_id: request.sessionId,
    },
  };
}

function toolResultStreamResponse(
  toolResult: ReturnType<typeof delegationToolResult>,
  request: ChatRequest,
): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "user",
      message: {
        role: "user",
        content: [toolResult],
      },
      session_id: request.sessionId,
    },
  };
}

